mapper.sql:
        
            and x1.types = #{vo.types}
        
        
            
                
                    MATCH(x1.name, x1.details) AGAINST(#{vo.name} IN BOOLEAN MODE)
                
                
                    and x1.name like CONCAT('%',#{vo.name},'%')
                
            
        

        
            and commodityTypes2.seconds like CONCAT('%',#{vo.typesName},'%')
        
        
            and x1.img like CONCAT('%',#{vo.img},'%')
        
        
            and x1.details like CONCAT('%',#{vo.details},'%')
        
        
            and x1.user_id = #{vo.userId}
        
        
            and x1.is_pub = #{vo.isPub}
        
        
            and x1.is_recom = #{vo.isRecom}
        
        
            and x1.is_update = #{vo.isUpdate}
        
        
            and exists (select 1 from tb_collect tb where tb.commodity_id=x1.id and tb.user_id=#{vo.userId})
        
        
            and x1.create_time >= #{vo.createTimeBegin}
        
        
            and x1.create_time <= #{vo.createTimeEnd}
        
        
            and x1.create_time >= #{vo.updateTimeBegin}
        
        
            and x1.create_time <= #{vo.updateTimeEnd}
        

        and x1.is_deleted = 0
        
        
            order by x1.${vo.orderCol} desc
        
        
            order by x1.create_time desc
